#include <bits/stdc++.h>
using namespace std;

// ── Return type, name, parameter list ──
int add(int a, int b) {
    return a + b;
}

// ── Void function: no return value ──
void greet(string name) {
    cout << "Hello, " << name << "!\n";
}

// ── Function with default parameters ──
void printLine(int count = 10, char symbol = '-') {
    for (int i = 0; i < count; i++) cout << symbol;
    cout << "\n";
}

// ── Forward declaration (prototype) ──
bool isPrime(int n);  // Declare before use

int main() {
    cout << add(3, 4) << "\n";  // 7
    greet("Ashik");              // Hello, Ashik!
    printLine();                 // ----------  (10 dashes)
    printLine(5, '*');           // *****
    cout << isPrime(17) << "\n"; // 1 (true)
    return 0;
}

// ── Definition can appear after main if prototype declared ──
bool isPrime(int n) {
    if (n < 2) return false;
    for (int i = 2; i * i <= n; i++)
        if (n % i == 0) return false;
    return true;
}

#include <bits/stdc++.h>
using namespace std;

// ── Pass by VALUE: works on a copy ──
void doubleVal(int x) {
    x *= 2;  // Only affects local copy
}

// ── Pass by REFERENCE: modifies original ──
void doubleRef(int& x) {
    x *= 2;  // Modifies the caller's variable
}

// ── Swap using references ──
void mySwap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

// ── Const reference: read-only, no copy overhead ──
// Best for large containers (vector, string) you don't want to modify
void printVector(const vector<int>& v) {
    for (int x : v) cout << x << " ";
    cout << "\n";
    // v.push_back(99); // COMPILE ERROR: v is const
}

int main() {
    int a = 5;
    doubleVal(a);
    cout << a << "\n";  // Still 5 — unchanged!

    doubleRef(a);
    cout << a << "\n";  // Now 10 — modified!

    int x = 3, y = 7;
    mySwap(x, y);
    cout << x << " " << y << "\n";  // 7 3

    vector<int> nums = {4, 2, 7, 1};
    printVector(nums);   // 4 2 7 1
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Factorial: n! = n * (n-1)!
// Base case: 0! = 1
long long factorial(int n) {
    if (n <= 0) return 1;          // BASE CASE
    return n * factorial(n - 1);  // RECURSIVE CASE
}

// Call stack trace for factorial(4):
// factorial(4)
//   = 4 * factorial(3)
//          = 3 * factorial(2)
//                 = 2 * factorial(1)
//                        = 1 * factorial(0)
//                                = 1  ← base case
//                        = 1 * 1 = 1
//                 = 2 * 1 = 2
//          = 3 * 2 = 6
//   = 4 * 6 = 24

int main() {
    for (int i = 0; i <= 10; i++)
        cout << i << "! = " << factorial(i) << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Naive: EXPONENTIAL — O(2^n). Only acceptable for n ≤ 30
long long fib_naive(int n) {
    if (n <= 1) return n;
    return fib_naive(n-1) + fib_naive(n-2);
}

// Memoized: O(n) — store computed results
map<int, long long> memo;
long long fib_memo(int n) {
    if (n <= 1) return n;
    if (memo.count(n)) return memo[n];   // already computed!
    return memo[n] = fib_memo(n-1) + fib_memo(n-2);
}

// Iterative: O(n) time, O(1) space — best for large n
long long fib_iter(int n) {
    if (n <= 1) return n;
    long long a = 0, b = 1;
    for (int i = 2; i <= n; i++) {
        long long c = a + b;
        a = b;
        b = c;
    }
    return b;
}

int main() {
    cout << fib_memo(50) << "\n";  // 12586269025
    cout << fib_iter(50) << "\n"; // 12586269025
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Compute base^exp % mod in O(log exp) — essential for CP!
long long power(long long base, long long exp, long long mod) {
    long long result = 1;
    base %= mod;
    while (exp > 0) {
        if (exp & 1)  // if exp is odd
            result = result * base % mod;
        base = base * base % mod;
        exp >>= 1;  // exp /= 2
    }
    return result;
}

// Recursive version (same idea)
long long rpow(long long b, long long e, long long m) {
    if (e == 0) return 1;
    if (e % 2 == 0) {
        long long half = rpow(b, e/2, m);
        return half * half % m;
    }
    return b * rpow(b, e-1, m) % m;
}

int main() {
    long long MOD = 1e9 + 7;
    cout << power(2, 10, MOD) << "\n";    // 1024
    cout << power(2, 30, MOD) << "\n";    // 1073741824
    cout << power(2, 1000000, MOD) << "\n"; // Fast! O(log n)
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Recursive GCD: O(log(min(a,b)))
int gcd(int a, int b) {
    if (b == 0) return a;  // base case
    return gcd(b, a % b);  // Euclidean step
}

// C++17: __gcd() and gcd() in <numeric>
// int g = __gcd(a, b);  // built-in

// LCM using GCD
long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;  // divide first to avoid overflow!
}

int main() {
    cout << gcd(48, 18) << "\n";     // 6
    cout << gcd(100, 75) << "\n";   // 25
    cout << lcm(4, 6) << "\n";      // 12
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Sum of array elements
int sumArray(int arr[], int n) {
    if (n == 0) return 0;                        // base: empty array
    return arr[0] + sumArray(arr + 1, n - 1);   // head + sum(tail)
}

// Maximum element
int maxArray(int arr[], int n) {
    if (n == 1) return arr[0];                   // base: single element
    return max(arr[0], maxArray(arr + 1, n-1)); // compare head to rest
}

// Check if array is sorted (ascending)
bool isSorted(int arr[], int n) {
    if (n <= 1) return true;                     // base: 0 or 1 elements
    if (arr[0] > arr[1]) return false;           // check adjacent pair
    return isSorted(arr + 1, n - 1);            // check rest
}

// Reverse a string using recursion
void reverseStr(string& s, int lo, int hi) {
    if (lo >= hi) return;   // base case
    swap(s[lo], s[hi]);
    reverseStr(s, lo + 1, hi - 1);
}

int main() {
    int arr[] = {3, 1, 4, 1, 5, 9, 2, 6};
    int n = 8;
    cout << sumArray(arr, n) << "\n";   // 31
    cout << maxArray(arr, n) << "\n";   // 9
    cout << isSorted(arr, n) << "\n";   // 0 (false)

    string s = "hello";
    reverseStr(s, 0, s.size()-1);
    cout << s << "\n";   // olleh
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Tail-recursive sum (accumulator pattern)
// Tail calls CAN be optimized by some compilers
long long sumTail(long long n, long long acc = 0) {
    if (n == 0) return acc;
    return sumTail(n - 1, acc + n);  // recursive call is LAST operation
}

// Iterative equivalent (always safe for large n)
long long sumIter(long long n) {
    return n * (n + 1) / 2;  // Gauss formula — O(1)!
}

int main() {
    // sumTail(1000000) might stack overflow!
    // sumIter(1000000) is always fine
    cout << sumIter(1000000) << "\n"; // 500000500000
    return 0;
}

