#include <bits/stdc++.h>
using namespace std;

int countDigits(long long n) {
    if (n < 10) return 1;             // base case: single digit
    return 1 + countDigits(n / 10);  // strip last digit, add 1
}

void solve() {
    long long n;
    cin >> n;
    cout << countDigits(n) << "\n";
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int t; cin >> t;
    while (t--) solve();
    return 0;
}

