// Implement power(base, exp) recursively using the
// 'fast exponentiation' (binary exponentiation) approach.
// base^exp: if exp is even → (base^(exp/2))²
//           if exp is odd  → base * base^(exp-1)
// No modulo needed for this problem.
// power(2, 10) → 1024, power(3, 5) → 243

sections.solution:
#include <bits/stdc++.h>
using namespace std;

long long power(long long base, int exp) {
    if (exp == 0) return 1;       // base case: anything^0 = 1
    if (exp % 2 == 0) {
        long long half = power(base, exp / 2);
        return half * half;       // IMPORTANT: store half to avoid double recursion
    } else {
        return base * power(base, exp - 1);
    }
}

void solve() {
    long long b; int e;
    cin >> b >> e;
    cout << power(b, e) << "\n";
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int t; cin >> t;
    while (t--) solve();
    return 0;
}
